import{_ as e,o,c as a,af as t}from"./chunks/framework.BSym9njW.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/03-infra/index.md","filePath":"zh/03-infra/index.md","lastUpdated":1778460716000}'),n={name:"zh/03-infra/index.md"};function l(s,r,i,h,c,d){return o(),a("div",null,[...r[0]||(r[0]=[t('<div align="center"><h1>03-Infra</h1><strong>⚙️ ROCm 算子优化与 GPU 编程</strong></div><div align="center"><p><em>从 AMD AI 硬件全景到 HIP 算子与性能分析</em></p><p><a href="/hello-rocm/zh/">返回主页</a></p></div><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>  本模块面向希望在 <strong>AMD GPU + ROCm</strong> 上建立系统认知的开发者：从 AI 硬件与 ROCm 软件栈全景，到 PyTorch 调用链与 GPU 架构，再到用 <strong>HIP</strong> 手写算子、结合 <strong>rocBLAS / MIOpen</strong> 与性能测量，把 ROCm 软件栈、GPU 编程与算子实践讲清楚、练到位。</p><p>  默认实验环境为 <strong>Ubuntu 22.04 / 24.04 + ROCm 7.x</strong>，示例设备以 <strong>AMD AI+ MAX395 / Radeon 8060S（gfx1151）</strong> 等为主，读者可按自身显卡与 ROCm 版本对照阅读。</p><h2 id="教程列表" tabindex="-1">教程列表 <a class="header-anchor" href="#教程列表" aria-label="Permalink to &quot;教程列表&quot;">​</a></h2><h3 id="第-1-章-拥抱-amd-ai-算力新时代" tabindex="-1">第 1 章：拥抱 AMD AI 算力新时代 <a class="header-anchor" href="#第-1-章-拥抱-amd-ai-算力新时代" aria-label="Permalink to &quot;第 1 章：拥抱 AMD AI 算力新时代&quot;">​</a></h3><p>  从 Ryzen AI（NPU + GPU）、Radeon 独显到 Instinct 数据中心加速卡，梳理 AMD AI 产品线与典型应用场景；说明 <strong>ROCm</strong> 在栈中的位置，并配合 <strong>PyTorch</strong> 完成 ResNet 训练与 Qwen 等大模型推理等动手实验，建立「能在 AMD 上跑什么」的整体图景。</p><ul><li><strong>适合人群</strong>：初次接触 AMD AI / ROCm 的开发者与学生</li><li><strong>难度等级</strong>：⭐⭐</li><li><strong>预计时间</strong>：2～3 小时</li></ul><p>📖 <a href="/hello-rocm/zh/03-infra/embrace-amd-ai">阅读第 1 章</a></p><hr><h3 id="第-2-章-解密-ai-加速器——从软件栈到硬件架构" tabindex="-1">第 2 章：解密 AI 加速器——从软件栈到硬件架构 <a class="header-anchor" href="#第-2-章-解密-ai-加速器——从软件栈到硬件架构" aria-label="Permalink to &quot;第 2 章：解密 AI 加速器——从软件栈到硬件架构&quot;">​</a></h3><p>  用 <code>ldd</code> 等工具追踪 <strong>PyTorch → HIP → HSA → 驱动 → GPU</strong> 的调用链路，理解 CPU「低延迟」与 GPU「高吞吐」、<strong>SIMT</strong> 执行模型；结合 <strong>CU、LDS、显存带宽</strong> 等概念，读懂 AMD GPU 在 AI 负载下的行为方式。</p><ul><li><strong>适合人群</strong>：已能跑通模型、希望理解底层栈与硬件的开发者</li><li><strong>难度等级</strong>：⭐⭐⭐</li><li><strong>预计时间</strong>：3～4 小时</li></ul><p>📖 <a href="/hello-rocm/zh/03-infra/decode-ai-accelerator">阅读第 2 章</a></p><hr><h3 id="第-3-章-迈入-rocm-编程世界——手写第一个-hip-算子" tabindex="-1">第 3 章：迈入 ROCm 编程世界——手写第一个 HIP 算子 <a class="header-anchor" href="#第-3-章-迈入-rocm-编程世界——手写第一个-hip-算子" aria-label="Permalink to &quot;第 3 章：迈入 ROCm 编程世界——手写第一个 HIP 算子&quot;">​</a></h3><p>  介绍 <strong>HIP</strong> 与 CUDA 的对应关系、Host/Device 代码结构；从 <strong>手写 Kernel</strong> 复现 Tensor 加法，到使用 <strong><code>hipEvent</code></strong> 做计时，并初步接触 <strong>rocBLAS</strong> 与 <strong>MIOpen</strong>，完成从 Python 到设备端代码的过渡。</p><ul><li><strong>适合人群</strong>：具备 C++ 基础、准备编写或阅读自定义算子的开发者</li><li><strong>难度等级</strong>：⭐⭐⭐</li><li><strong>预计时间</strong>：2～3 小时</li></ul><p>📖 <a href="/hello-rocm/zh/03-infra/handwrite-rocm-operator">阅读第 3 章</a></p><hr><h3 id="第-4-章-为-pytorch-编写自定义-rocm-算子" tabindex="-1">第 4 章：为 PyTorch 编写自定义 ROCm 算子 <a class="header-anchor" href="#第-4-章-为-pytorch-编写自定义-rocm-算子" aria-label="Permalink to &quot;第 4 章：为 PyTorch 编写自定义 ROCm 算子&quot;">​</a></h3><p>  从 PyTorch 的 Python 调用链出发，用 <strong>C++ Extension</strong> 机制将 HIP Kernel 注册为自定义算子；实战 <strong>Fused Swish</strong> 算子、<strong>Grid-Stride Loop</strong> 优化、<strong>Autograd</strong> 自动求导集成，并通过 <strong>内存墙基准测试</strong> 量化带宽瓶颈，完成从「手写 Kernel」到「PyTorch 可调用算子」的完整闭环。</p><ul><li><strong>适合人群</strong>：希望将自定义 HIP 算子集成到 PyTorch 训练/推理流程的开发者</li><li><strong>难度等级</strong>：⭐⭐⭐⭐</li><li><strong>预计时间</strong>：3～4 小时</li></ul><p>📖 <a href="/hello-rocm/zh/03-infra/custom-pytorch-operator">阅读第 4 章</a></p><hr><h2 id="环境要求" tabindex="-1">环境要求 <a class="header-anchor" href="#环境要求" aria-label="Permalink to &quot;环境要求&quot;">​</a></h2><h3 id="硬件要求" tabindex="-1">硬件要求 <a class="header-anchor" href="#硬件要求" aria-label="Permalink to &quot;硬件要求&quot;">​</a></h3><ul><li>AMD GPU（支持 ROCm 的显卡，如 RX 7000 / 9000 系列、Ryzen AI MAX / AI 300、Instinct MI 系列等）</li><li>各章实验对显存要求不同：第 1 章涉及 ResNet / 大模型推理时请预留足够显存；第 3、4 章以小型 HIP 程序与矩阵实验为主，一般消费级显卡即可</li></ul><h3 id="软件要求" tabindex="-1">软件要求 <a class="header-anchor" href="#软件要求" aria-label="Permalink to &quot;软件要求&quot;">​</a></h3><ul><li>操作系统：Linux（Ubuntu 22.04+，教程正文以 22.04 / 24.04 为例）</li><li>ROCm 7.10.0 或更高版本（章节内亦可能出现 7.x 表述，以你本机 <code>rocm-smi</code> / 发行说明为准）</li><li>第 1 章：Python 3.10+、PyTorch（ROCm 构建版）</li><li>第 3、4 章：建议安装 <strong>ROCm HIP 开发组件</strong>（如 <code>hipcc</code>、<code>rocm-dev</code> 等，随发行版包名可能略有差异）、CMake 3.16+、GCC 9+ 或 Clang 12+</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><details><summary>Q: 如何确认我的 AMD GPU 是否支持 ROCm？</summary><p>请参考 <a href="https://rocm.docs.amd.com/projects/install-on-linux/en/latest/reference/system-requirements.html" target="_blank" rel="noreferrer">ROCm 官方支持列表</a> 查看支持的 GPU 型号与发行版组合。</p></details><details><summary>Q: 第 3、4 章与第 1、2 章是什么关系？</summary><p>第 1、2 章侧重<strong>全景与栈/硬件认知</strong>；第 3、4 章侧重<strong>HIP 编程与算子级实践</strong>。两章标题相近：可先读第 3 章建立最小闭环，再读第 4 章做映射与性能深化；若时间有限，也可按个人基础选读其中一章。</p></details><details><summary>Q: 编译 HIP 程序时提示找不到头文件或链接库？</summary><ol><li>确认已安装对应版本的 ROCm 开发包，且 <code>hipcc</code> 在 <code>PATH</code> 中</li><li>检查 <code>HIP_PATH</code>、<code>ROCM_PATH</code> 等环境变量是否与安装路径一致</li><li>参考 <a href="https://rocm.docs.amd.com/projects/HIP/en/latest/" target="_blank" rel="noreferrer">HIP 安装与入门</a> 核对依赖</li></ol></details><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://rocm.docs.amd.com/" target="_blank" rel="noreferrer">ROCm 官方文档</a></li><li><a href="https://rocm.docs.amd.com/projects/HIP/en/latest/" target="_blank" rel="noreferrer">HIP 编程指南</a></li><li><a href="https://rocm.docs.amd.com/projects/rocBLAS/en/latest/" target="_blank" rel="noreferrer">rocBLAS 文档</a></li><li><a href="https://rocm.docs.amd.com/projects/MIOpen/en/latest/" target="_blank" rel="noreferrer">MIOpen 文档</a></li><li><a href="https://pytorch.org/get-started/locally/" target="_blank" rel="noreferrer">PyTorch for ROCm</a></li></ul><hr><div align="center"><p><strong>欢迎贡献更多算子优化与 GPU 编程实践内容！</strong> 🎉</p><p><a href="https://github.com/datawhalechina/hello-rocm/issues" target="_blank" rel="noreferrer">提交 Issue</a> | <a href="https://github.com/datawhalechina/hello-rocm/pulls" target="_blank" rel="noreferrer">提交 PR</a></p></div>',39)])])}const p=e(n,[["render",l]]);export{g as __pageData,p as default};
